#include <iostream>

class Rectangle {
    long long width_;
    long long height_;
public:
    Rectangle(long long width, long long height) : width_(width < 0 ? 0 : width), height_(height < 0 ? 0 : height) {}
    long long area() const { return width_ * height_; }
};

int main() {
    long long width{}, height{};
    if (!(std::cin >> width >> height)) return 1;
    Rectangle rectangle(width, height);
    std::cout << rectangle.area() << '\n';
}
